# ============================================================
# BLING — Topology Evaluation Harness
# ============================================================
# PURPOSE:
#   Evaluates synthetic laundering graph topologies generated by
#   the Red Team against existing detection heuristics. Determines
#   which graph flow structures evade current detection logic.
#
#   This is NOT a production fraud detection system.
#   This is a sandboxed robustness-testing harness for research.
#
# SCOPE:
#   The harness evaluates topology-level evasion only.
#   It does NOT retrain, adapt, or improve autonomously.
#   Results are passed to the Escape Analyzer for pattern export.
#
# ARCHITECTURE POSITION:
#   Generator → Mutator → Kafka → Graph Engine
#   → [THIS SERVICE] Topology Evaluation Harness
#   → Escape Analyzer → Graph Pattern Exporter
# ============================================================
import logging
import os
import sys
import time
from contextlib import asynccontextmanager
from datetime import datetime
from typing import Any, Dict, List, Optional
from uuid import uuid4

import structlog
from fastapi import FastAPI, HTTPException, Query
from fastapi.middleware.cors import CORSMiddleware

sys.path.insert(0, "/app")
sys.path.insert(0, "/app/streaming")

from graph_heuristics import GraphHeuristicsDetector
from topology_evaluator import TopologyEvaluator
from rule_heuristics import RuleEngine

try:
    from streaming.consumer import RedTeamConsumer
    from streaming.producer import RedTeamProducer
    from streaming.topics import Topics
except ImportError:
    from consumer import RedTeamConsumer
    from producer import RedTeamProducer
    from topics import Topics

logging.basicConfig(level=os.getenv("LOG_LEVEL", "INFO"))
log = structlog.get_logger()

# ─── Config ───────────────────────────────────────────────
KAFKA_SERVERS = os.getenv("KAFKA_BOOTSTRAP_SERVERS", "localhost:29092")
GRAPH_ENGINE_URL = os.getenv("GRAPH_ENGINE_URL", "http://graph-engine:8002")

# Evasion threshold: topology risk score below this is considered
# a successful evasion of baseline heuristics.
EVASION_THRESHOLD = float(os.getenv("EVASION_THRESHOLD", "0.5"))

# ─── State ────────────────────────────────────────────────
_rule_engine: Optional[RuleEngine] = None
_graph_detector: Optional[GraphHeuristicsDetector] = None
_topology_evaluator: Optional[TopologyEvaluator] = None
_consumer: Optional[RedTeamConsumer] = None
_producer: Optional[RedTeamProducer] = None

# Evaluation results log
_evaluations: List[Dict[str, Any]] = []
_stats = {
    "total_topologies_evaluated": 0,
    "total_detected_by_rules": 0,
    "total_detected_by_graph": 0,
    "total_detected_by_baseline": 0,
    "total_evaded": 0,
}


def _compute_combined_risk(rule_r: float, graph_r: float, topo_r: float) -> float:
    """
    Weighted combination of heuristic scores.
    Represents probability that this graph topology would be flagged
    by an existing detection system.
    """
    return min(1.0, rule_r * 0.35 + graph_r * 0.40 + topo_r * 0.25)


def _on_topology_event(txn: Dict[str, Any]) -> None:
    """
    Process a synthetic transaction from a generated graph topology.
    Evaluates whether the topology structure evades existing heuristics.
    """
    global _stats
    t_start = time.monotonic()

    try:
        # ── Evaluate against three heuristic layers ────────────
        rule_result = _rule_engine.evaluate(txn)
        graph_result = _graph_detector.evaluate(txn)
        topo_result = _topology_evaluator.evaluate(txn)

        rule_risk = rule_result.get("rule_risk_score", 0.0)
        graph_risk = graph_result.get("graph_risk_score", 0.0)
        topo_risk = topo_result.get("topology_risk_score", 0.0)

        combined_risk = _compute_combined_risk(rule_risk, graph_risk, topo_risk)
        latency_ms = (time.monotonic() - t_start) * 1000

        _stats["total_topologies_evaluated"] += 1

        # ── Determine evasion outcome ──────────────────────────
        evades_heuristics = combined_risk < EVASION_THRESHOLD

        if rule_risk >= EVASION_THRESHOLD:
            _stats["total_detected_by_rules"] += 1
        if graph_risk >= EVASION_THRESHOLD:
            _stats["total_detected_by_graph"] += 1
        if topo_result.get("evades_baseline", False):
            _stats["total_detected_by_baseline"] += 1

        if evades_heuristics:
            _stats["total_evaded"] += 1

        # ── Build evaluation record ────────────────────────────
        eval_id = f"eval_{uuid4().hex[:12]}"
        evaluation = {
            "evaluation_id": eval_id,
            "transaction_id": txn.get("transaction_id"),
            "simulation_id": txn.get("simulation_id"),
            # Graph topology metadata
            "topology_type": txn.get("attack_type"),
            "mutation_generation": txn.get("mutation_generation", 0),
            "sender_account": txn.get("sender_account"),
            "receiver_account": txn.get("receiver_account"),
            "amount": txn.get("amount"),
            # Heuristic evaluation scores
            "combined_risk_score": round(combined_risk, 4),
            "rule_heuristic_score": round(rule_risk, 4),
            "graph_heuristic_score": round(graph_risk, 4),
            "baseline_topology_score": round(topo_risk, 4),
            # Evasion outcome
            "evades_heuristics": evades_heuristics,
            "triggered_rules": rule_result.get("triggered_rules", []),
            "graph_signals": graph_result.get("graph_signals", []),
            # Metadata
            "evaluation_latency_ms": round(latency_ms, 2),
            "timestamp": datetime.utcnow().isoformat() + "Z",
            "_simulation": True,
        }

        _evaluations.append(evaluation)

        # ── Publish evasion events to Escape Analyzer ─────────
        if evades_heuristics:
            _producer.publish(
                topic=Topics.ALERTS,
                payload=evaluation,
                key=txn.get("simulation_id"),
            )
            log.info(
                "Topology evaded heuristics",
                topology_type=txn.get("attack_type"),
                mutation_gen=txn.get("mutation_generation", 0),
                combined_risk=combined_risk,
                simulation_id=txn.get("simulation_id"),
            )
        else:
            log.debug(
                "Topology detected by heuristics",
                topology_type=txn.get("attack_type"),
                combined_risk=combined_risk,
            )

    except Exception as e:
        log.error("Topology evaluation failed", error=str(e), exc_info=True)


def _classify_evasion_type(rule_result: Dict, graph_result: Dict) -> str:
    """Classify what type of heuristic the topology successfully evaded."""
    rules = {r["rule"] for r in rule_result.get("triggered_rules", [])}
    signals = {s["signal"] for s in graph_result.get("graph_signals", [])}

    if "cycle_participant" in signals:
        return "cyclic_topology"
    if "high_centrality_sender" in signals or "high_centrality_receiver" in signals:
        return "hub_topology"
    if "velocity_burst" in rules:
        return "velocity_topology"
    if "structuring" in rules:
        return "structuring_topology"
    if "large_amount" in rules:
        return "high_value_topology"
    return "unknown_topology_variation"


@asynccontextmanager
async def lifespan(app: FastAPI):
    global _rule_engine, _graph_detector, _topology_evaluator, _consumer, _producer
    log.info("Topology Evaluation Harness starting...")

    _rule_engine = RuleEngine(
        structuring_threshold=float(os.getenv("STRUCTURING_THRESHOLD", "10000")),
        velocity_window=int(os.getenv("VELOCITY_WINDOW_SECONDS", "300")),
    )
    _graph_detector = GraphHeuristicsDetector(
        graph_engine_url=GRAPH_ENGINE_URL,
        high_centrality_threshold=float(os.getenv("HIGH_CENTRALITY_THRESHOLD", "0.7")),
    )

    # Initialize fixed benchmark evaluator ONCE — never retrained
    _topology_evaluator = TopologyEvaluator(
        contamination=float(os.getenv("BASELINE_CONTAMINATION", "0.15"))
    )
    _topology_evaluator.initialize()

    _producer = RedTeamProducer(KAFKA_SERVERS)
    _consumer = RedTeamConsumer(
        bootstrap_servers=KAFKA_SERVERS,
        group_id=os.getenv("KAFKA_GROUP_ID_DETECTOR", "harness-group"),
        topics=[Topics.TRANSACTIONS],
        handler=_on_topology_event,
    )
    _consumer.start()
    log.info(
        "Topology Evaluation Harness ready. "
        "Consuming synthetic topology stream. "
        "Fixed benchmark model will NOT retrain."
    )
    yield

    _consumer.stop()
    _graph_detector.close()
    _producer.close()
    log.info("Topology Evaluation Harness shut down")


app = FastAPI(
    title="BLING — Topology Evaluation Harness",
    description=(
        "Evaluates synthetic laundering graph topologies against static detection heuristics. "
        "Determines which graph flow structures evade existing rule-based and baseline ML checks. "
        "Research/Sandbox use only — NOT a production fraud detection system."
    ),
    version="2.0.0",
    lifespan=lifespan,
)
app.add_middleware(CORSMiddleware, allow_origins=["*"], allow_methods=["*"], allow_headers=["*"])


# ─── Endpoints ────────────────────────────────────────────

@app.get("/health")
async def health():
    return {
        "status": "healthy",
        "service": "topology-evaluation-harness",
        "total_topologies_evaluated": _stats["total_topologies_evaluated"],
        "total_evaded": _stats["total_evaded"],
        "evaluator_ready": _topology_evaluator.is_initialized if _topology_evaluator else False,
        "evaluator_total_scored": _topology_evaluator.total_evaluated if _topology_evaluator else 0,
        "_simulation": True,
        "note": "Fixed benchmark model — does not retrain or adapt",
    }


@app.get("/evaluations")
async def get_evaluations(
    limit: int = Query(default=50, le=500),
    simulation_id: Optional[str] = None,
    evaded_only: bool = False,
):
    """Return topology evaluation results."""
    data = _evaluations[-500:]
    if simulation_id:
        data = [e for e in data if e.get("simulation_id") == simulation_id]
    if evaded_only:
        data = [e for e in data if e.get("evades_heuristics", False)]
    return {
        "evaluations": data[-limit:],
        "total": len(data),
    }


@app.get("/evaluations/{simulation_id}")
async def get_evaluations_by_sim(simulation_id: str, limit: int = 100):
    """Return evaluation results for a specific simulation run."""
    data = [e for e in _evaluations if e.get("simulation_id") == simulation_id]
    return {
        "simulation_id": simulation_id,
        "evaluations": data[-limit:],
        "count": len(data),
        "evaded_count": sum(1 for e in data if e.get("evades_heuristics", False)),
    }


@app.get("/alerts/{simulation_id}")
async def get_alerts_compat(simulation_id: str, limit: int = 100):
    """Compatibility endpoint — returns evasion events for simulation runner."""
    data = [e for e in _evaluations if e.get("simulation_id") == simulation_id]
    evasions = [e for e in data if e.get("evades_heuristics", False)]
    return {"simulation_id": simulation_id, "count": len(evasions)}


@app.get("/stats")
async def get_stats():
    """Aggregate evaluation statistics across all topology runs."""
    total = _stats["total_topologies_evaluated"]
    evaded = _stats["total_evaded"]
    return {
        **_stats,
        "evasion_rate": round(evaded / total, 4) if total > 0 else 0.0,
        "detection_rate": round((total - evaded) / total, 4) if total > 0 else 0.0,
        "evaluator_initialized": _topology_evaluator.is_initialized if _topology_evaluator else False,
        "scope": "sandbox_research_only",
    }
